import { useParams, Link } from "react-router-dom";
import { useState, useEffect } from "react";
import Card from "../components/Card";

export default function RoadmapPage() {
  const { name } = useParams();

  const [domain, setDomain] = useState("");
  const [journeyStarted, setJourneyStarted] = useState(false);
  const [learningStarted, setLearningStarted] = useState(false);
  const [currentDay, setCurrentDay] = useState(1);
  const [completedDays, setCompletedDays] = useState([]);

  const timeline = localStorage.getItem("timeline") || "3 months";
  const totalDays = parseInt(timeline) * 30;

  // 🔥 HANDLE DOMAIN CHANGE + RESET
  useEffect(() => {
    const newDomain =
      (name || localStorage.getItem("selectedDomain") || "ai-and-ml").toLowerCase();

    const prevDomain = localStorage.getItem("selectedDomain");

    if (prevDomain && prevDomain !== newDomain) {
      // 🔥 RESET EVERYTHING
      localStorage.removeItem("journeyStarted");
      localStorage.removeItem("learningStarted");
      localStorage.removeItem("currentDay");
      localStorage.removeItem("carryForward");
      localStorage.removeItem("completedDays");
      localStorage.removeItem("dailyCompleted");
    }

    localStorage.setItem("selectedDomain", newDomain);

    setDomain(newDomain);
    setJourneyStarted(localStorage.getItem("journeyStarted") === "true");
    setLearningStarted(localStorage.getItem("learningStarted") === "true");
    setCurrentDay(parseInt(localStorage.getItem("currentDay") || "1"));
    setCompletedDays(JSON.parse(localStorage.getItem("completedDays") || "[]"));

  }, [name]);

  // 🔥 DOMAIN TOPICS
  const topicMap = {
    "ai-and-ml": [
      ["Python Basics → Datatypes"],
      ["Variables & Input/Output"],
      ["Loops", "Conditions"],
      ["Functions"],
      ["NumPy"],
      ["Pandas"],
      ["Visualization"],
      ["Statistics"],
      ["ML Algorithms"],
      ["Deep Learning"],
      ["Neural Networks"],
      ["Project"]
    ],

    "web-development": [
      ["HTML Basics"],
      ["CSS Styling"],
      ["Flexbox"],
      ["JavaScript Basics"],
      ["DOM"],
      ["React"],
      ["Hooks"],
      ["API"],
      ["Backend"],
      ["Database"],
      ["Deployment"],
      ["Project"]
    ]
  };

  const topics = topicMap[domain] || [["Basics"]];

  const getTasksForDay = (day) => {
    const index = (day - 1) % topics.length;
    return topics[index];
  };

  // 🔥 BUTTONS
  const handleStartJourney = () => {
    localStorage.setItem("journeyStarted", "true");
    setJourneyStarted(true);
  };

  const handleStartToday = () => {
    localStorage.setItem("learningStarted", "true");
    localStorage.setItem("currentDay", 1);
    localStorage.setItem("completedDays", "[]");

    setLearningStarted(true);
    setCurrentDay(1);
    setCompletedDays([]);
  };

  // 🔥 PROGRESS
  const progress = Math.min((currentDay / totalDays) * 100, 100);

  return (
    <div className="space-y-8">
      <Card title="Learning Roadmap">

        {/* 📊 Progress */}
        {learningStarted && (
          <div className="mb-4">
            <div className="w-full bg-gray-200 h-3 rounded-full">
              <div
                className="bg-teal-500 h-3 rounded-full"
                style={{ width: `${progress}%` }}
              />
            </div>
            <p className="text-sm mt-1">{Math.floor(progress)}% completed</p>
          </div>
        )}

        {/* 🔥 STEP 1: DOMAIN OVERVIEW */}
        {!journeyStarted && (
          <div className="text-center space-y-4">

            <h3 className="text-xl font-semibold">
              📚 What you will learn in this journey
            </h3>

            <div className="grid gap-4 mt-4">
              {topics.map((t, i) => (
                <div
                  key={i}
                  className="p-4 rounded-xl bg-green-100 border border-teal-300"
                >
                  <strong>Day {i + 1}</strong>
                  <ul className="mt-2 text-sm">
                    {t.map((topic, idx) => (
                      <li key={idx}>👉 {topic}</li>
                    ))}
                  </ul>
                </div>
              ))}
            </div>

            <button
              onClick={handleStartJourney}
              className="mt-4 px-6 py-3 bg-teal-500 text-white rounded-xl"
            >
              Start Your Journey 🚀
            </button>

          </div>
        )}

        {/* 🔥 STEP 2 */}
        {journeyStarted && !learningStarted && (
          <div className="text-center space-y-4">

            <h3 className="text-lg font-semibold">
              Ready to start learning?
            </h3>

            <button
              onClick={handleStartToday}
              className="px-6 py-3 bg-teal-600 text-white rounded-xl"
            >
              Start From Today 📅
            </button>

          </div>
        )}

        {/* 🔥 STEP 3 */}
        {learningStarted && (
          <div className="space-y-4">

            <h3 className="text-lg font-semibold">
              📅 Day {currentDay}
            </h3>

            {getTasksForDay(currentDay).map((task, i) => (
              <div key={i} className="p-3 bg-green-100 rounded-lg">
                {task}
              </div>
            ))}

            <Link to="/tasks">
              <button className="mt-4 px-4 py-2 bg-teal-500 text-white rounded-lg">
                Go to Tasks →
              </button>
            </Link>

          </div>
        )}

        {/* 📅 CALENDAR */}
        {learningStarted && (
          <div className="mt-6">
            <h3 className="font-semibold mb-2">📅 Calendar</h3>

            <div className="grid grid-cols-7 gap-2">
              {Array.from({ length: totalDays }).map((_, i) => {
                const day = i + 1;

                return (
                  <div
                    key={day}
                    className={`p-2 text-center rounded text-xs ${
                      completedDays.includes(day)
                        ? "bg-teal-400 text-white"
                        : day === currentDay
                        ? "bg-yellow-300"
                        : "bg-gray-200"
                    }`}
                  >
                    {day}
                  </div>
                );
              })}
            </div>
          </div>
        )}

      </Card>
    </div>
  );
}
